unsigned long contended, res;

	do {
		__asm__ __volatile__(
			"	ldrex	%0, [%2]\n"
			"	mov	%1, #0\n"
			"	teq	%0, #0\n"
			"	strexeq	%1, %3, [%2]"
			: "=&r" (contended), "=&r" (res)
			: "r" (&lock->lock), "r" (1)
			: "cc");
	} while (res);

	if (contended == 0) {
		smp_mb();
		return 1;
	} else {
		return 0;
	}这是不阻塞的自旋锁吗

